SELECT count(*) FROM company_name, movie_companies, title, kind_type, movie_info, movie_keyword, keyword, cast_info WHERE movie_companies.company_id = company_name.id AND movie_companies.movie_id = title.id AND title.kind_id = kind_type.id AND movie_info.movie_id = title.id AND movie_keyword.movie_id = title.id AND movie_keyword.keyword_id = keyword.id AND cast_info.movie_id = title.id;